  private String getValueHyperLink(int fieldDomainId, String fieldName, int filterDateDomainId, String filterDateValue, String apName, String path, int sheetIndex, List<NUIFilter> filters) {
    String filterDate = filterDateValue != null && !filterDateValue.isEmpty() ? String.format("&pql%d=%s", filterDateDomainId, filterDateValue) : "";
    String domainIdValuePair = fieldDomainId + "=" + fieldName;
    StringBuilder fv2 = new StringBuilder();
    for (NUIFilter filter : filters) {
      if (fieldDomainId == filter.getDomainId() || (filterDateDomainId == filter.getDomainId() && !filterDate.isEmpty())) continue;
      for (String filterString : filter.getFilterV2String()) {
        fv2.append("&fv2=").append(filterString);
      }
    }
    return String.format("/%s%s/%d?pqv%s%s%s", apName, path, sheetIndex, domainIdValuePair, filterDate, fv2);
  }

