  if(!(""+decimalSep+thousandsSep).equals(".,")){
    decimalFormat=decimalFormat.replace(thousandsSep, '`').replace(decimalSep,'.').replace('`',',');
  }
  RankingAdder rankingAdder=new RankingAdder(year,month);
